from datetime import datetime, timedelta
import xml.etree.ElementTree as ET

def check_bing_freshness(bing_xml: str, max_age_days: int = 90) -> bool:
    try:
        root = ET.fromstring(bing_xml)
        for result in root.findall('.//{http://schemas.microsoft.com/search/local/ws/rest/v1}NewsResult'):
            pub_date = result.find('{http://schemas.microsoft.com/search/local/ws/rest/v1}Date')
            if pub_date is not None:
                pub_dt = datetime.fromisoformat(pub_date.text.replace('Z', '+00:00'))
                if datetime.now(pub_dt.tzinfo) - pub_dt > timedelta(days=max_age_days):
                    return False
        return True
    except:
        return False

# Check Azure Agent grounding data
agent_response = client.agents.get_last_exchange(thread_id)
if not check_bing_freshness(agent_response.grounding_data):
    print('🚨 Stale Bing grounding data detected')

