from vex_sdk import VexMiddleware
from azure.ai.projects import AgentExtension

class PolicyFilterMiddleware(VexMiddleware):
    def __init__(self):
        self.blocked_patterns = [
            r'\b(?:SSN|credit\s*card)\b',
            r'\b\d{3}-\d{2}-\d{4}\b'
        ]

    def process_tool_output(self, tool_call, output: str) -> str:
        for pattern in self.blocked_patterns:
            if re.search(pattern, output, re.IGNORECASE):
                self.log_violation(tool_call, 'PII_DETECTED')
                return 'Output blocked by enterprise policy'
        return output

# Register with Azure AI Agent Service
middleware = PolicyFilterMiddleware()
agent_extension = AgentExtension(
    middleware=middleware,
    trigger_on=['tool_call']
)
client.agents.create_extension(agent_id, agent_extension)

class GroundingRouter(VexMiddleware):
    def route_grounding_data(self, grounding_sources: list) -> list:
        fresh_sources = []
        for source in grounding_sources:
            if source.provider == 'bing' and not self.is_fresh(source):
                self.log('Routing stale Bing to enterprise KB')
                fresh_sources.append(self.query_enterprise_kb(source.query))
            else:
                fresh_sources.append(source)
        return fresh_sources

    def is_fresh(self, source) -> bool:
        if 'publish_date' in source.metadata:
            return (datetime.now() - source.metadata['publish_date']).days < 30
        return True

# Install router in Azure pipeline
router = GroundingRouter()
client.agents.update_pipeline(
    agent_id,
    middleware=[router],
    stage='grounding'
)
